      <div className="grid grid-cols-1 md:grid-cols-2 gap-12 lg:gap-24">
        {PROJECTS.map((project, index) => (
          <div 
            key={project.id} 
            onClick={() => setSelectedProject(project)}
            className={`group relative cursor-pointer ${index % 2 !== 0 ? 'md:mt-32' : ''}`}
