interface ProjectsGridProps {
  lang: Language;
}

const ProjectsGrid: React.FC<ProjectsGridProps> = ({ lang }) => {
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);
  const [hoveredProject, setHoveredProject] = useState<Project | null>(null);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const t = TRANSLATIONS[lang].projects;
  const listRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (selectedProject) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
  }, [selectedProject]);

  const handleMouseMove = (e: React.MouseEvent) => {
    setMousePos({ x: e.clientX, y: e.clientY });
  };

  return (
    <section 
      id="projects" 
      className="py-32 px-6 md:px-12 bg-[#F9F7F2] relative min-h-screen"
      onMouseMove={handleMouseMove}
    >
      <div className="flex flex-col md:flex-row justify-between items-baseline mb-24 gap-6">
        <h2 className="font-archivo text-5xl md:text-7xl uppercase tracking-tighter">
          {t.title}
        </h2>
        <p className="max-w-md font-medium text-neutral-500 text-lg">
          {t.description}
        </p>
      </div>

      {/* Floating Preview Image */}
      <div 
        className={`fixed z-40 pointer-events-none transition-opacity duration-500 ease-out overflow-hidden hidden lg:block ${hoveredProject ? 'opacity-100' : 'opacity-0'}`}
        style={{
          left: mousePos.x,
          top: mousePos.y,
          width: '400px',
          height: '500px',
          transform: 'translate(40px, -50%) rotate(2deg)',
          transition: 'opacity 0.5s ease-out, transform 0.1s linear'
