  useEffect(() => {
    if (selectedProject) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
  }, [selectedProject]);

  const handleMouseMove = (e: React.MouseEvent) => {
    setMousePos({ x: e.clientX, y: e.clientY });
  };

  return (
    <section 
      id="projects" 
      className="py-32 bg-[#F9F7F2] relative"
      onMouseMove={handleMouseMove}
    >
      <div className="px-6 md:px-12 mb-24 flex flex-col md:flex-row justify-between items-baseline gap-12">
        <h2 className="font-archivo text-6xl md:text-8xl uppercase tracking-tighter">{t.title}</h2>
        <p className="max-w-md font-medium text-neutral-500 text-lg leading-relaxed">{t.description}</p>
      </div>

      {/* SECTION 1: Featured Hero Tiles */}
      <div className="px-6 md:px-12 grid grid-cols-1 md:grid-cols-2 gap-12 md:gap-24 mb-32">
        {featuredProjects.map((project, index) => (
          <div 
            key={project.id} 
            onClick={() => setSelectedProject(project)}
            className={`group relative cursor-pointer ${index % 2 !== 0 ? 'md:mt-32' : ''}`}
          >
            <div className="overflow-hidden relative aspect-[4/5] bg-neutral-200">
              <div className={`absolute inset-0 z-10 transition-transform duration-700 ease-[cubic-bezier(0.83,0,0.17,1)] translate-y-full group-hover:translate-y-0 ${project.color} opacity-90`}></div>
              <img src={project.image} alt={project.title[lang]} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" />
              <div className="absolute inset-0 z-20 flex flex-col justify-center items-center opacity-0 group-hover:opacity-100 transition-opacity duration-500 p-8 text-white text-center">
                 <span className="font-archivo text-xs uppercase tracking-widest mb-4">{project.category[lang]}</span>
                 <h3 className="font-archivo text-4xl md:text-5xl uppercase tracking-tighter">{project.title[lang]}</h3>
                 <div className="mt-8 border border-white px-6 py-2 uppercase text-xs tracking-widest hover:bg-white hover:text-black transition-colors duration-300">
                    {t.viewProject}
                 </div>
              </div>
            </div>
            <div className="mt-6 flex justify-between items-center group-hover:px-2 transition-all duration-300">
              <h3 className="font-archivo text-xl uppercase tracking-tight">{project.title[lang]}</h3>
              <span className="font-editorial italic text-xl text-neutral-400">{project.category[lang]}</span>
            </div>
          </div>
        ))}
      </div>

      {/* SECTION 2: Typographic List Archive */}
      <div className="relative border-t border-black/10">
        {/* Floating Preview Image (Only for List Section) */}
        <div 
          className={`fixed z-40 pointer-events-none transition-opacity duration-500 ease-out hidden lg:block ${hoveredProject ? 'opacity-100' : 'opacity-0'}`}
          style={{
            left: mousePos.x,
            top: mousePos.y,
            width: '320px',
            height: '420px',
            transform: 'translate(40px, -50%) rotate(3deg)',
            transition: 'opacity 0.5s ease-out, transform 0.15s linear'
          }}
        >
          <div className="w-full h-full relative bg-neutral-100 shadow-2xl">
             {archiveProjects.map((p) => (
               <img 
                 key={p.id}
                 src={p.image} 
                 alt=""
                 className={`absolute inset-0 w-full h-full object-cover transition-opacity duration-500 ${hoveredProject?.id === p.id ? 'opacity-100' : 'opacity-0'}`}
               />
             ))}
          </div>
        </div>

        <div className="flex flex-col">
          {archiveProjects.map((project, index) => (
            <div 
              key={project.id}
              onMouseEnter={() => setHoveredProject(project)}
              onMouseLeave={() => setHoveredProject(null)}
              onClick={() => setSelectedProject(project)}
              className="group relative px-6 md:px-12 flex items-center justify-between py-10 md:py-16 border-b border-black/10 cursor-pointer transition-colors duration-500 hover:bg-neutral-900/5"
            >
              <div className="flex items-baseline gap-6 md:gap-12 relative z-10">
                <span className="font-archivo text-xs md:text-sm text-neutral-300 transition-colors group-hover:text-orange-500">
                  0{index + 3}
                </span>
                <h3 className={`font-editorial font-bold text-4xl md:text-[7vw] leading-none uppercase italic tracking-tighter transition-all duration-700 ${hoveredProject && hoveredProject.id !== project.id ? 'opacity-10' : 'opacity-100'}`}>
                  {project.title[lang]}
                </h3>
              </div>

              <div className={`hidden md:flex flex-col items-end text-right transition-all duration-700 ${hoveredProject && hoveredProject.id !== project.id ? 'opacity-10' : 'opacity-100'}`}>
                 <span className="font-archivo text-[10px] uppercase tracking-[0.4em] text-neutral-400 mb-2">
                   {project.category[lang]}
                 </span>
                 <div className={`h-[1px] bg-black/20 transition-all duration-500 ${hoveredProject?.id === project.id ? 'w-24 bg-orange-500' : 'w-12'}`}></div>
              </div>

              {/* Mobile Preview */}
              <div className="md:hidden w-16 h-16 rounded-full overflow-hidden flex-shrink-0 ml-4 border border-black/10">
                 <img src={project.image} alt="" className="w-full h-full object-cover" />
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Project Detail Modal */}
      {selectedProject && (
        <div className="fixed inset-0 z-[100] bg-[#F9F7F2] overflow-y-auto animate-in fade-in slide-in-from-bottom-10 duration-500">
          <button 
            onClick={() => setSelectedProject(null)}
            className="fixed top-8 right-8 z-[110] bg-orange-500 text-white w-14 h-14 md:w-20 md:h-20 flex items-center justify-center rounded-full hover:scale-110 active:scale-95 transition-transform duration-300 shadow-xl"
            aria-label="Close project"
          >
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-6 h-6 md:w-8 md:h-8">
              <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>

          <div className="max-w-7xl mx-auto px-6 md:px-12 py-32">
            <div className="mb-24">
              <div className="flex items-center gap-4 mb-8">
                <span className="font-archivo text-xs uppercase tracking-[0.4em] text-orange-500">{t.detailLabel}</span>
                <div className="h-[1px] flex-1 bg-black/10"></div>
              </div>

              <h1 className="font-archivo text-6xl md:text-[10vw] leading-[0.8] uppercase tracking-tighter mb-12">
                {selectedProject.title[lang]}
              </h1>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-12 items-end">
                <div className="space-y-6">
                  <span className="font-editorial italic text-3xl md:text-5xl text-neutral-400 block">
                    {selectedProject.category[lang]}
                  </span>
                  <p className="font-editorial text-2xl md:text-4xl leading-tight text-neutral-800 italic max-w-xl">
                    {selectedProject.description[lang]}
                  </p>
                </div>
                <div className="flex flex-col gap-2 font-archivo text-[10px] uppercase tracking-widest text-neutral-400 text-right">
                  <span>Client: Private Collector</span>
                  <span>Year: 2024</span>
                  <span>Discipline: Branding & Design</span>
                </div>
              </div>
            </div>

            <div className="space-y-12 md:space-y-24">
              {selectedProject.gallery.map((img, i) => (
                <div key={i} className="relative group overflow-hidden bg-neutral-100">
                  <img src={img} alt={`${selectedProject.title[lang]} ${i}`} className="w-full h-auto max-h-[120vh] object-cover" />
                </div>
              ))}
            </div>

            <div className="mt-32 py-16 border-t border-black/10 flex flex-col items-center">
              <p className="font-editorial text-4xl italic mb-8">{t.nextProject}</p>
              <button 
                onClick={() => {
                  const currentIndex = PROJECTS.findIndex(p => p.id === selectedProject.id);
                  const nextIndex = (currentIndex + 1) % PROJECTS.length;
                  setSelectedProject(PROJECTS[nextIndex]);
                  window.scrollTo(0, 0);
                }}
                className="font-archivo text-4xl md:text-7xl uppercase tracking-tighter hover:text-orange-500 transition-colors"
              >
                {PROJECTS[(PROJECTS.findIndex(p => p.id === selectedProject.id) + 1) % PROJECTS.length].title[lang]}
              </button>
            </div>
          </div>
        </div>
      )}
    </section>
  );
};

export default ProjectsGrid;

