import React, { useState, useEffect, useRef } from 'react';
import { PROJECTS, TRANSLATIONS } from '../constants';
import { Project, Language } from '../types';

interface ProjectsGridProps {
  lang: Language;
}

const ProjectsGrid: React.FC<ProjectsGridProps> = ({ lang }) => {
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const t = TRANSLATIONS[lang].projects;

  useEffect(() => {
    if (selectedProject) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
  }, [selectedProject]);

  const scroll = (direction: 'left' | 'right') => {
    if (scrollRef.current) {
      const { scrollLeft, clientWidth } = scrollRef.current;
      const scrollTo = direction === 'left' ? scrollLeft - clientWidth : scrollLeft + clientWidth;
      scrollRef.current.scrollTo({ left: scrollTo, behavior: 'smooth' });
    }
  };

  return (
    <section 
      id="projects" 
      className="py-32 bg-[#F9F7F2] relative overflow-hidden"
    >
      {/* Header Info */}
      <div className="px-6 md:px-12 mb-16 flex flex-col md:flex-row justify-between items-end gap-12">
        <div className="max-w-2xl">
          <h2 className="font-archivo text-6xl md:text-8xl uppercase tracking-tighter mb-6">{t.title}</h2>
          <p className="font-medium text-neutral-500 text-lg leading-relaxed">{t.description}</p>
        </div>

        {/* Navigation Buttons */}
        <div className="hidden md:flex gap-4 mb-2">
          <button 
            onClick={() => scroll('left')}
            className="w-16 h-16 rounded-full border border-black/10 flex items-center justify-center hover:bg-black hover:text-white transition-all duration-300"
            aria-label="Scroll Left"
          >
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6">
              <path strokeLinecap="round" strokeLinejoin="round" d="M10.5 19.5L3 12m0 0l7.5-7.5M3 12h18" />
            </svg>
          </button>
          <button 
            onClick={() => scroll('right')}
            className="w-16 h-16 rounded-full border border-black/10 flex items-center justify-center hover:bg-black hover:text-white transition-all duration-300"
            aria-label="Scroll Right"
          >
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6">
              <path strokeLinecap="round" strokeLinejoin="round" d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" />
            </svg>
          </button>
        </div>
      </div>

      {/* Horizontal Slider */}
      <div 
        ref={scrollRef}
        className="flex overflow-x-auto gap-6 px-6 md:px-12 no-scrollbar scroll-smooth snap-x snap-mandatory pb-12"
        style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
      >
        {PROJECTS.map((project, index) => (
          <div 
            key={project.id}
            onClick={() => setSelectedProject(project)}
            className="min-w-[85vw] md:min-w-[calc(50vw-48px)] snap-start group cursor-pointer"
          >
            <div className="relative aspect-[16/10] overflow-hidden bg-neutral-200 transition-transform duration-700 ease-out group-hover:scale-[1.02]">
              {/* Pop of Color Overlay */}
              <div className={`absolute inset-0 z-10 transition-transform duration-700 ease-[cubic-bezier(0.83,0,0.17,1)] translate-y-full group-hover:translate-y-0 ${project.color} opacity-90`}></div>

              <img 
                src={project.image} 
                alt={project.title[lang]} 
                className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" 
