                <h3 className="font-archivo text-3xl uppercase tracking-tighter mb-6 group-hover:translate-x-2 transition-transform duration-300">{service.title}</h3>
                <p className="text-lg text-neutral-500 leading-relaxed font-medium">{service.desc}</p>
              </div>
            ))}
          </div>
        </Section>

        <ProjectsGrid lang={lang} />

        <Section id="studio" title={t.studio.title} subtitle={t.studio.subtitle} className="bg-magic-black text-off-white">
          <div className="flex flex-col lg:flex-row gap-12 items-center">
            <div className="lg:w-1/2">
              <img src="https://images.unsplash.com/photo-1497366216548-37526070297c?auto=format&fit=crop&q=80&w=1200" alt="Studio" className="w-full grayscale hover:grayscale-0 transition-all duration-700" />
            </div>
            <div className="lg:w-1/2 space-y-8">
              <p className="font-editorial text-4xl italic text-neutral-300">{t.studio.p1}</p>
              <p className="text-xl text-neutral-400 font-light leading-relaxed">{t.studio.p2}</p>
              <button className="bg-magic-orange text-white font-archivo uppercase tracking-widest px-10 py-5 hover:bg-orange-600 transition-colors">
                {t.studio.startProject}
              </button>
            </div>
          </div>
        </Section>

        <Section id="contact" title={t.contact.title} subtitle={t.contact.subtitle}>
          <div className="flex flex-col md:flex-row gap-16 mt-12">
            <div className="md:w-1/2 space-y-12">
              <div>
                <span className="font-archivo text-xs uppercase tracking-widest text-neutral-400 block mb-4">{t.contact.emailLabel}</span>
                <a href="mailto:hello@magicpop.studio" className="font-archivo text-3xl md:text-5xl uppercase tracking-tighter hover:text-magic-orange transition-colors duration-300 underline underline-offset-8 decoration-neutral-200">hello@magicpop.studio</a>
              </div>
              <div>
                <span className="font-archivo text-xs uppercase tracking-widest text-neutral-400 block mb-4">{t.contact.followLabel}</span>
                <div className="flex gap-8 font-archivo uppercase text-sm tracking-widest">
                  <a href="#" className="hover:text-magic-blue transition-colors">Instagram</a>
                  <a href="#" className="hover:text-magic-blue transition-colors">Behance</a>
                </div>
              </div>
            </div>
            <div className="md:w-1/2 bg-yellow-400 p-12 flex flex-col justify-center">
              <p className="font-editorial text-3xl md:text-5xl text-magic-black italic leading-tight mb-8">{t.contact.footerNote}</p>
              <button className="bg-magic-black text-off-white font-archivo uppercase tracking-widest px-10 py-5 hover:bg-neutral-800 transition-colors self-start">{t.studio.startProject}</button>
            </div>
          </div>
        </Section>
      </main>

      <footer className="bg-magic-black py-16 px-6 md:px-12 text-off-white flex flex-col md:flex-row justify-between items-center gap-8">
        <div className="font-archivo text-xl uppercase tracking-tighter">Magic Pop<span className="font-editorial lowercase text-lg ml-1">studio</span></div>
        <div className="text-xs uppercase tracking-widest text-neutral-500">© 2024 Magic Pop Studio. RAL 8022 Inspired Palette.</div>
      </footer>
