import React, { useState, useEffect, useRef, useMemo } from 'react';
import { PROJECTS, TRANSLATIONS } from '../constants';
import { Project, Language } from '../types';

interface ProjectsGridProps {
  lang: Language;
}

const ProjectsGrid: React.FC<ProjectsGridProps> = ({ lang }) => {
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);
  const [activeFilter, setActiveFilter] = useState<string | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const t = TRANSLATIONS[lang].projects;

  // Extract unique categories based on current language
  const categories = useMemo(() => {
    const cats = PROJECTS.map(p => p.category[lang]);
    return Array.from(new Set(cats));
  }, [lang]);

  // Filter projects based on selection
  const filteredProjects = useMemo(() => {
    if (!activeFilter) return PROJECTS;
    return PROJECTS.filter(p => p.category[lang] === activeFilter);
  }, [activeFilter, lang]);

  useEffect(() => {
    if (selectedProject) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
  }, [selectedProject]);

  // Reset scroll position when filter changes
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({ left: 0, behavior: 'smooth' });
    }
  }, [activeFilter]);

  const scroll = (direction: 'left' | 'right') => {
    if (scrollRef.current) {
      const { scrollLeft, clientWidth } = scrollRef.current;
      const scrollTo = direction === 'left' ? scrollLeft - clientWidth : scrollLeft + clientWidth;
      scrollRef.current.scrollTo({ left: scrollTo, behavior: 'smooth' });
    }
  };

  return (
    <section 
      id="projects" 
      className="py-32 bg-off-white dark:bg-magic-dark relative overflow-hidden transition-colors duration-500"
    >
      {/* Header Info */}
      <div className="px-6 md:px-12 mb-16 flex flex-col md:flex-row justify-between items-end gap-12">
        <div className="max-w-2xl">
          <h2 className="font-archivo text-6xl md:text-8xl uppercase tracking-tighter mb-6 text-magic-black dark:text-off-white">{t.title}</h2>
          <p className="font-medium text-neutral-500 dark:text-neutral-400 text-lg leading-relaxed mb-10">{t.description}</p>

          {/* Filter Bar */}
          <div className="flex flex-wrap gap-x-8 gap-y-4">
            <button 
              onClick={() => setActiveFilter(null)}
              className={`font-archivo text-xs uppercase tracking-widest transition-all duration-300 relative pb-1 ${!activeFilter ? 'text-magic-orange' : 'text-neutral-400 hover:text-magic-black dark:hover:text-off-white'}`}
            >
              {t.featured || (lang === 'de' ? 'Alle' : 'All')}
              {!activeFilter && <span className="absolute bottom-0 left-0 w-full h-[2px] bg-magic-orange"></span>}
            </button>
            {categories.map((cat) => (
              <button 
                key={cat}
                onClick={() => setActiveFilter(cat)}
                className={`font-archivo text-xs uppercase tracking-widest transition-all duration-300 relative pb-1 ${activeFilter === cat ? 'text-magic-orange' : 'text-neutral-400 hover:text-magic-black dark:hover:text-off-white'}`}
              >
                {cat}
                {activeFilter === cat && <span className="absolute bottom-0 left-0 w-full h-[2px] bg-magic-orange"></span>}
              </button>
            ))}
          </div>
        </div>

        {/* Navigation Buttons */}
        <div className="hidden md:flex gap-4 mb-2">
          <button 
            onClick={() => scroll('left')}
            className="w-16 h-16 rounded-full border border-magic-black/10 dark:border-off-white/10 flex items-center justify-center hover:bg-magic-black hover:text-white dark:hover:bg-off-white dark:hover:text-magic-black dark:hover:shadow-[0_0_20px_rgba(255,255,255,0.2)] transition-all duration-300"
            aria-label="Scroll Left"
          >
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6">
              <path strokeLinecap="round" strokeLinejoin="round" d="M10.5 19.5L3 12m0 0l7.5-7.5M3 12h18" />
            </svg>
          </button>
          <button 
            onClick={() => scroll('right')}
            className="w-16 h-16 rounded-full border border-magic-black/10 dark:border-off-white/10 flex items-center justify-center hover:bg-magic-black hover:text-white dark:hover:bg-off-white dark:hover:text-magic-black dark:hover:shadow-[0_0_20px_rgba(255,255,255,0.2)] transition-all duration-300"
            aria-label="Scroll Right"
          >
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6">
              <path strokeLinecap="round" strokeLinejoin="round" d="M13.5 4.5L21 12m0 0l-7.5-7.5M21 12H3" />
            </svg>
          </button>
        </div>
      </div>

      {/* Horizontal Slider */}
      <div 
        ref={scrollRef}
        className="flex overflow-x-auto gap-6 px-6 md:px-12 no-scrollbar scroll-smooth snap-x snap-mandatory pb-12 min-h-[400px]"
      >
        {filteredProjects.length > 0 ? (
          filteredProjects.map((project, index) => (
            <div 
              key={project.id}
              onClick={() => setSelectedProject(project)}
              className="min-w-[85vw] md:min-w-[calc(50vw-48px)] snap-start group cursor-pointer animate-in"
              style={{ animationDelay: `${index * 50}ms` }}
            >
              <div className="relative aspect-[16/10] overflow-hidden bg-neutral-200 dark:bg-neutral-800 transition-all duration-700 ease-out group-hover:scale-[1.02] group-hover:shadow-[0_20px_60px_-15px_rgba(0,0,0,0.3)] dark:group-hover:shadow-[0_20px_60px_-15px_rgba(255,77,0,0.3)] rounded-sm">
                <div className={`absolute inset-0 z-10 transition-transform duration-700 ease-[cubic-bezier(0.83,0,0.17,1)] translate-y-full group-hover:translate-y-0 ${project.color} opacity-90`}></div>

                <img 
                  src={project.image} 
                  alt={project.title[lang]} 
                  className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-110" 
                />

                <div className="absolute inset-0 z-20 flex flex-col justify-center items-center opacity-0 group-hover:opacity-100 transition-opacity duration-500 p-8 text-white text-center">
                   <span className="font-archivo text-xs uppercase tracking-[0.3em] mb-4 transition-all duration-700 ease-out translate-y-4 group-hover:translate-y-0 group-hover:scale-110">
                    {project.category[lang]}
