interface HeroProps {
  lang: Language;
}

const Hero: React.FC<HeroProps> = ({ lang }) => {
  const t = TRANSLATIONS[lang].hero;
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const [blobPos, setBlobPos] = useState({ x: 0, y: 0 });
  const requestRef = useRef<number>(null);

  // Maus-Tracker
  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      setMousePos({ x: e.clientX, y: e.clientY });
    };

    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  // Smooth Follow (Lerp Animation)
  useEffect(() => {
    const animate = () => {
      setBlobPos((prev) => ({
        x: prev.x + (mousePos.x - prev.x) * 0.05,
        y: prev.y + (mousePos.y - prev.y) * 0.05,
      }));
      requestRef.current = requestAnimationFrame(animate);
    };

    requestRef.current = requestAnimationFrame(animate);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [mousePos]);

  return (
    <section id="hero" className="relative min-h-screen flex flex-col justify-center px-6 md:px-12 pt-24 pb-12 overflow-hidden bg-off-white dark:bg-magic-dark transition-colors duration-500">

      {/* Interaktiver Hintergrund-Blob */}
      <div 
        className="pointer-events-none fixed inset-0 z-0 overflow-hidden"
        style={{ perspective: '1000px' }}
      >
        <div 
          className="absolute w-[40vw] h-[40vw] max-w-[500px] max-h-[500px] rounded-full bg-magic-orange blur-[140px] opacity-35 dark:opacity-55 mix-blend-multiply dark:mix-blend-screen transition-opacity duration-700"
          style={{
            left: blobPos.x,
            top: blobPos.y,
            transform: 'translate(-50%, -50%)',
            willChange: 'left, top'
          }}
        />
        {/* Zusätzlicher statischer Akzent-Blob für Tiefe */}
        <div className="absolute top-1/4 -left-20 w-64 h-64 rounded-full bg-magic-blue blur-[120px] opacity-10 dark:opacity-20 animate-pulse"></div>
      </div>

      <div className="relative z-10">
        <h1 className="font-archivo text-[15vw] leading-[0.85] uppercase tracking-tighter text-magic-black dark:text-off-white flex flex-col">
          <span className="relative inline-block">Magic</span>
          <span className="text-right -mt-[2vw] relative inline-block">Pop</span>
        </h1>

        <div className="mt-12 max-w-4xl">
          <p className="font-editorial text-4xl md:text-7xl leading-tight text-magic-black dark:text-off-white italic animate-in" style={{ animationDelay: '200ms' }}>
            {t.subline} <br />
            <span className="font-archivo not-italic text-3xl md:text-6xl uppercase tracking-tight text-magic-blue dark:text-magic-orange transition-colors duration-700">
              {t.sublineBold}
            </span>
          </p>
        </div>
      </div>

      <div className="mt-auto flex justify-between items-end relative z-10 animate-in" style={{ animationDelay: '400ms' }}>
        <div className="flex flex-col gap-2">
           <span className="text-xs uppercase tracking-[0.3em] font-black text-neutral-400 dark:text-neutral-500">{t.location}</span>
           <span className="text-xs uppercase tracking-[0.3em] font-black text-neutral-400 dark:text-neutral-500">{t.est}</span>
        </div>
        <div className="animate-bounce text-magic-black dark:text-off-white">
           <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-8 h-8">
              <path strokeLinecap="round" strokeLinejoin="round" d="M19.5 13.5L12 21m0 0l-7.5-7.5M12 21V3" />
           </svg>
        </div>
      </div>
    </section>
  );
};

