import Section from './components/Section';
import { Language } from './types';
import { TRANSLATIONS } from './constants';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('de');
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const [blobPos, setBlobPos] = useState({ x: 0, y: 0 });
  const requestRef = useRef<number>(null);

  const [headerTheme, setHeaderTheme] = useState({
    bg: 'bg-transparent',
    text: 'text-magic-black dark:text-off-white',
    shadow: '',
    blobColor: 'bg-magic-orange'
  });

  const t = TRANSLATIONS[lang];

  // Maus-Tracking für den globalen Blob
  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      setMousePos({ x: e.clientX, y: e.clientY });
    };
    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  // Smooth Follow Animation (Lerp)
  useEffect(() => {
    const animate = () => {
      setBlobPos((prev) => ({
        x: prev.x + (mousePos.x - prev.x) * 0.06,
        y: prev.y + (mousePos.y - prev.y) * 0.06,
      }));
      requestRef.current = requestAnimationFrame(animate);
    };
    requestRef.current = requestAnimationFrame(animate);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [mousePos]);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  useEffect(() => {
    const handleScroll = () => {
      const scrollPos = window.scrollY + 120;
      const whatWeDo = document.getElementById('what-we-do');
      const projects = document.getElementById('projects');
      const studio = document.getElementById('studio');
      const contact = document.getElementById('contact');

      if (contact && scrollPos >= contact.offsetTop) {
        setHeaderTheme({ 
          bg: 'bg-magic-pink', 
          text: 'text-magic-black', 
          shadow: 'dark:shadow-[0_10px_40px_-10px_rgba(255,183,213,0.6)]',
          blobColor: 'bg-magic-pink'
        });
      } else if (studio && scrollPos >= studio.offsetTop) {
        setHeaderTheme({ 
          bg: 'bg-magic-blue', 
          text: 'text-white', 
          shadow: 'dark:shadow-[0_10px_40px_-10px_rgba(0,56,255,0.6)]',
          blobColor: 'bg-magic-blue'
        });
      } else if (projects && scrollPos >= projects.offsetTop) {
        setHeaderTheme({ 
          bg: 'bg-magic-orange', 
          text: 'text-white', 
          shadow: 'dark:shadow-[0_10px_40px_-10px_rgba(255,77,0,0.6)]',
          blobColor: 'bg-magic-orange'
        });
      } else if (whatWeDo && scrollPos >= whatWeDo.offsetTop) {
        setHeaderTheme({ 
          bg: 'bg-magic-orange', 
          text: 'text-white', 
          shadow: 'dark:shadow-[0_10px_40px_-10px_rgba(255,77,0,0.6)]',
          blobColor: 'bg-magic-orange'
        });
      } else {
        setHeaderTheme({ 
          bg: 'bg-transparent', 
          text: 'text-magic-black dark:text-off-white', 
          shadow: '',
          blobColor: 'bg-magic-orange'
        });
      }
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const toggleDarkMode = () => setIsDarkMode(!isDarkMode);

  return (
    <div className="relative overflow-hidden selection:bg-magic-orange selection:text-white bg-off-white dark:bg-magic-dark transition-colors duration-500">

      {/* Globaler interaktiver Hintergrund-Blob */}
      <div className="pointer-events-none fixed inset-0 z-0 overflow-hidden">
        <div 
          className={`absolute w-[45vw] h-[45vw] max-w-[600px] max-h-[600px] rounded-full blur-[140px] opacity-40 dark:opacity-60 transition-all duration-1000 ease-in-out ${headerTheme.blobColor}`}
          style={{
            left: blobPos.x,
            top: blobPos.y,
            transform: 'translate(-50%, -50%)',
            willChange: 'left, top'
          }}
        />
        {/* Statischer Akzent-Blob */}
        <div className="absolute top-1/3 -left-20 w-80 h-80 rounded-full bg-magic-blue blur-[160px] opacity-10 dark:opacity-20"></div>
      </div>

      <Header 
        bgColor={`${headerTheme.bg} ${headerTheme.shadow}`} 
        textColor={headerTheme.text} 
        lang={lang} 
        setLang={setLang} 
        isDarkMode={isDarkMode}
        toggleDarkMode={toggleDarkMode}
      />

      <main className="relative z-10">
        <Hero lang={lang} />

        <Section id="what-we-do" title={t.whatWeDo.title} subtitle={t.whatWeDo.subtitle} className="bg-transparent">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-12 mt-12">
            {t.whatWeDo.services.map((service, i) => (
              <div key={i} className="group border-t border-magic-black/10 dark:border-off-white/10 pt-8 hover:border-magic-black dark:hover:border-off-white transition-colors duration-500">
                <span className="font-archivo text-sm uppercase tracking-widest mb-4 block opacity-40">0{i+1}</span>
                <h3 className="font-archivo text-3xl uppercase tracking-tighter mb-6 group-hover:translate-x-2 transition-transform duration-300">{service.title}</h3>
                <p className="text-lg text-neutral-500 dark:text-neutral-400 leading-relaxed font-medium">{service.desc}</p>
              </div>
            ))}
          </div>
        </Section>

        <ProjectsGrid lang={lang} />

        <Section id="studio" title={t.studio.title} subtitle={t.studio.subtitle} className="bg-magic-black/95 text-off-white dark:bg-black/90 backdrop-blur-sm">
          <div className="flex flex-col lg:flex-row gap-12 items-center">
            <div className="lg:w-1/2">
              <img src="https://images.unsplash.com/photo-1497366216548-37526070297c?auto=format&fit=crop&q=80&w=1200" alt="Studio" className="w-full grayscale hover:grayscale-0 transition-all duration-700 rounded-sm" />
            </div>
            <div className="lg:w-1/2 space-y-8">
              <p className="font-editorial text-4xl italic text-neutral-300">{t.studio.p1}</p>
              <p className="text-xl text-neutral-400 font-light leading-relaxed">{t.studio.p2}</p>
              <button className="bg-magic-orange text-white font-archivo uppercase tracking-widest px-10 py-5 hover:bg-orange-600 transition-all duration-300 dark:shadow-[0_0_25px_rgba(255,77,0,0.4)] dark:hover:shadow-[0_0_40px_rgba(255,77,0,0.6)]">
                {t.studio.startProject}
              </button>
            </div>
          </div>
        </Section>

        <Section id="contact" title={t.contact.title} subtitle={t.contact.subtitle} className="bg-transparent">
          <div className="flex flex-col md:flex-row gap-16 mt-12">
            <div className="md:w-1/2 space-y-12">
              <div>
                <span className="font-archivo text-xs uppercase tracking-widest text-neutral-400 block mb-4">{t.contact.emailLabel}</span>
                <a href="mailto:hello@magicpop.studio" className="font-archivo text-3xl md:text-5xl uppercase tracking-tighter hover:text-magic-orange transition-colors duration-300 underline underline-offset-8 decoration-neutral-200 dark:decoration-neutral-800">hello@magicpop.studio</a>
              </div>
              <div>
                <span className="font-archivo text-xs uppercase tracking-widest text-neutral-400 block mb-4">{t.contact.followLabel}</span>
                <div className="flex gap-8 font-archivo uppercase text-sm tracking-widest">
                  <a href="#" className="hover:text-magic-blue transition-colors">Instagram</a>
                  <a href="#" className="hover:text-magic-blue transition-colors">Behance</a>
                </div>
              </div>
            </div>
            <div className="md:w-1/2 bg-yellow-400/90 p-12 flex flex-col justify-center dark:shadow-[0_0_50px_rgba(250,204,21,0.2)] backdrop-blur-sm">
              <p className="font-editorial text-3xl md:text-5xl text-magic-black italic leading-tight mb-8">{t.contact.footerNote}</p>
              <button className="bg-magic-black text-off-white font-archivo uppercase tracking-widest px-10 py-5 hover:bg-neutral-800 transition-all duration-300 self-start dark:shadow-[0_0_20px_rgba(0,0,0,0.5)]">
                {t.studio.startProject}
              </button>
