                      {t.viewProject}
                   </div>
                </div>
              </div>

              <div className="mt-8 flex justify-between items-start">
                <div>
                  <h3 className="font-archivo text-2xl uppercase tracking-tighter mb-1 text-magic-black dark:text-off-white">{project.title[lang]}</h3>
                  <p className="font-editorial text-xl italic text-neutral-400 dark:text-neutral-500">{project.category[lang]}</p>
                </div>
                <div className="w-10 h-10 rounded-full border border-magic-black/10 dark:border-off-white/10 flex items-center justify-center group-hover:bg-magic-orange group-hover:border-magic-orange transition-all duration-300 group-hover:rotate-45 dark:group-hover:shadow-[0_0_15px_rgba(255,77,0,0.5)]">
                   <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-4 h-4 group-hover:text-white transition-colors text-magic-black dark:text-off-white">
                      <path strokeLinecap="round" strokeLinejoin="round" d="M4.5 19.5l15-15m0 0H8.25m11.25 0v11.25" />
                   </svg>
                </div>
              </div>
            </div>
          ))
        ) : (
          <div className="w-full flex justify-center py-20">
             <p className="font-editorial italic text-3xl text-neutral-400">No projects found in this category.</p>
