import React, { useState, useEffect, useRef } from 'react';
import Header from './components/Header';
import Hero from './components/Hero';
import ProjectsGrid from './components/ProjectsGrid';
import Section from './components/Section';
import { Language } from './types';
import { TRANSLATIONS } from './constants';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('de');
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const [blob1Pos, setBlob1Pos] = useState({ x: 0, y: 0 });
  const [blob2Pos, setBlob2Pos] = useState({ x: 0, y: 0 });
  const requestRef = useRef<number>(null);

  const [headerTheme, setHeaderTheme] = useState({
    bg: 'bg-transparent',
    text: 'text-magic-black dark:text-off-white',
    shadow: '',
    blobColor: 'bg-magic-orange'
  });

  const t = TRANSLATIONS[lang];

  // Maus-Tracking
  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      setMousePos({ x: e.clientX, y: e.clientY });
    };
    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  // Smooth Follow Animation für zwei Blobs (Duo-System)
  useEffect(() => {
    const animate = () => {
      setBlob1Pos((prev) => ({
        x: prev.x + (mousePos.x - prev.x) * 0.08,
        y: prev.y + (mousePos.y - prev.y) * 0.08,
      }));
      setBlob2Pos((prev) => ({
        x: prev.x + (mousePos.x - prev.x) * 0.04,
        y: prev.y + (mousePos.y - prev.y) * 0.04,
      }));
      requestRef.current = requestAnimationFrame(animate);
    };
    requestRef.current = requestAnimationFrame(animate);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [mousePos]);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  useEffect(() => {
    const handleScroll = () => {
      const scrollPos = window.scrollY + 120;
      const whatWeDo = document.getElementById('what-we-do');
      const projects = document.getElementById('projects');
      const studio = document.getElementById('studio');
      const contact = document.getElementById('contact');

      if (contact && scrollPos >= contact.offsetTop) {
        setHeaderTheme({ 
          bg: 'bg-magic-pink', 
          text: 'text-magic-black', 
          shadow: 'dark:shadow-[0_10px_40px_-10px_rgba(255,183,213,0.6)]',
          blobColor: 'bg-magic-pink'
        });
      } else if (studio && scrollPos >= studio.offsetTop) {
        setHeaderTheme({ 
          bg: 'bg-magic-blue', 
          text: 'text-white', 
          shadow: 'dark:shadow-[0_10px_40px_-10px_rgba(0,56,255,0.6)]',
          blobColor: 'bg-magic-blue'
        });
      } else if (projects && scrollPos >= projects.offsetTop) {
        setHeaderTheme({ 
          bg: 'bg-magic-orange', 
          text: 'text-white', 
          shadow: 'dark:shadow-[0_10px_40px_-10px_rgba(255,77,0,0.6)]',
          blobColor: 'bg-magic-orange'
        });
      } else if (whatWeDo && scrollPos >= whatWeDo.offsetTop) {
        setHeaderTheme({ 
          bg: 'bg-magic-orange', 
          text: 'text-white', 
          shadow: 'dark:shadow-[0_10px_40px_-10px_rgba(255,77,0,0.6)]',
          blobColor: 'bg-magic-orange'
        });
      } else {
        setHeaderTheme({ 
          bg: 'bg-transparent', 
          text: 'text-magic-black dark:text-off-white', 
          shadow: '',
          blobColor: 'bg-magic-orange'
        });
      }
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const toggleDarkMode = () => setIsDarkMode(!isDarkMode);

  return (
    <div className="relative overflow-hidden selection:bg-magic-orange selection:text-white bg-off-white dark:bg-magic-dark transition-colors duration-500">

      {/* Globales Duo-Blob System im Hintergrund */}
      <div className="pointer-events-none fixed inset-0 z-0 overflow-hidden">
        <div 
          className={`absolute w-[45vw] h-[45vw] max-w-[600px] max-h-[600px] rounded-full blur-[140px] opacity-50 dark:opacity-60 transition-colors duration-1000 ease-in-out ${headerTheme.blobColor}`}
          style={{
            left: blob1Pos.x,
            top: blob1Pos.y,
            transform: 'translate(-50%, -50%)',
            willChange: 'left, top'
          }}
        />
        <div 
          className={`absolute w-[35vw] h-[35vw] max-w-[500px] max-h-[500px] rounded-full blur-[160px] opacity-40 dark:opacity-50 transition-colors duration-1000 ease-in-out ${headerTheme.blobColor}`}
          style={{
            left: blob2Pos.x,
            top: blob2Pos.y,
            transform: 'translate(-50%, -50%)',
            willChange: 'left, top'
          }}
        />
        <div className="absolute top-1/3 -left-20 w-80 h-80 rounded-full bg-magic-blue blur-[180px] opacity-10 dark:opacity-20"></div>
      </div>

      <Header 
        bgColor={`${headerTheme.bg} ${headerTheme.shadow}`} 
        textColor={headerTheme.text} 
        lang={lang} 
        setLang={setLang} 
        isDarkMode={isDarkMode}
        toggleDarkMode={toggleDarkMode}
      />

      <main className="relative z-10">
        <Hero lang={lang} />

        <Section id="what-we-do" title={t.whatWeDo.title} subtitle={t.whatWeDo.subtitle} className="bg-transparent">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-12 mt-12">
            {t.whatWeDo.services.map((service, i) => (
              <div key={i} className="group border-t border-magic-black/10 dark:border-off-white/10 pt-8 hover:border-magic-black dark:hover:border-off-white transition-colors duration-500">
                <span className="font-archivo text-sm uppercase tracking-widest mb-4 block text-magic-black/40 dark:text-off-white/40">0{i+1}</span>
                <h3 className="font-archivo text-3xl uppercase tracking-tighter mb-6 text-magic-black dark:text-off-white group-hover:translate-x-2 transition-transform duration-300">{service.title}</h3>
                <p className="text-lg text-magic-black/60 dark:text-off-white/60 leading-relaxed font-medium">{service.desc}</p>
              </div>
            ))}
          </div>
        </Section>

        <ProjectsGrid lang={lang} />

        {/* Studio Sektion mit semi-transparentem Hintergrund, damit der Blob hindurchscheint */}
        <Section id="studio" title={t.studio.title} subtitle={t.studio.subtitle} className="bg-magic-black/90 text-off-white dark:bg-black/90 backdrop-blur-3xl transition-colors duration-500">
          <div className="flex flex-col lg:flex-row gap-12 items-center">
            <div className="lg:w-1/2">
              <div className="relative group overflow-hidden rounded-sm">
                <img src="https://images.unsplash.com/photo-1497366216548-37526070297c?auto=format&fit=crop&q=80&w=1200" alt="Studio" className="w-full grayscale group-hover:grayscale-0 transition-all duration-700 scale-105 group-hover:scale-100" />
