              <button className="bg-magic-orange text-white font-archivo uppercase tracking-widest px-10 py-5 hover:bg-orange-600 transition-all duration-300 shadow-[0_10px_30px_rgba(255,77,0,0.3)] hover:shadow-[0_15px_40px_rgba(255,77,0,0.5)]">
                {t.studio.startProject}
              </button>
            </div>
          </div>
