import React, { useState, useEffect, useRef } from 'react';
import Header from './components/Header';
import Hero from './components/Hero';
import ProjectsGrid from './components/ProjectsGrid';
import Section from './components/Section';
import { Language } from './types';
import { TRANSLATIONS } from './constants';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('de');
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [mousePos, setMousePos] = useState({ x: -500, y: -500 });
  const [blob1Pos, setBlob1Pos] = useState({ x: 0, y: 0 });
  const [blob2Pos, setBlob2Pos] = useState({ x: 0, y: 0 });
  const requestRef = useRef<number>(null);

  const [headerTheme, setHeaderTheme] = useState({
    bg: 'bg-transparent',
    text: 'text-magic-black dark:text-off-white',
    shadow: '',
    blobColor: 'bg-magic-orange'
  });

  const t = TRANSLATIONS[lang];

  // Mouse & Touch Tracking
  useEffect(() => {
    const handleMove = (e: MouseEvent | TouchEvent) => {
      const x = 'touches' in e ? e.touches[0].clientX : e.clientX;
      const y = 'touches' in e ? e.touches[0].clientY : e.clientY;
      setMousePos({ x, y });
    };

    window.addEventListener('mousemove', handleMove);
    window.addEventListener('touchmove', handleMove, { passive: true });

    if (mousePos.x === -500) {
      setMousePos({ x: window.innerWidth / 2, y: window.innerHeight / 2 });
    }

    return () => {
      window.removeEventListener('mousemove', handleMove);
      window.removeEventListener('touchmove', handleMove);
    };
  }, []);

  // Smooth Follow Animation
  useEffect(() => {
    let time = 0;
    const animate = () => {
      time += 0.01;
      const driftX = Math.sin(time * 0.5) * 20;
      const driftY = Math.cos(time * 0.3) * 20;

      setBlob1Pos((prev) => ({
        x: prev.x + (mousePos.x + driftX - prev.x) * 0.06,
        y: prev.y + (mousePos.y + driftY - prev.y) * 0.06,
      }));
      setBlob2Pos((prev) => ({
        x: prev.x + (mousePos.x - driftX - prev.x) * 0.03,
        y: prev.y + (mousePos.y - driftY - prev.y) * 0.03,
      }));
      requestRef.current = requestAnimationFrame(animate);
    };
    requestRef.current = requestAnimationFrame(animate);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [mousePos]);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  useEffect(() => {
    const handleScroll = () => {
      const scrollPos = window.scrollY + 120;
      const whatWeDo = document.getElementById('what-we-do');
      const projects = document.getElementById('projects');
      const studio = document.getElementById('studio');
      const contact = document.getElementById('contact');

      if (contact && scrollPos >= contact.offsetTop) {
        setHeaderTheme({ 
          bg: 'bg-magic-pink', 
          text: 'text-magic-black', 
          shadow: 'dark:shadow-[0_10px_40px_-10px_rgba(255,183,213,0.6)]',
          blobColor: 'bg-magic-pink'
        });
      } else if (studio && scrollPos >= studio.offsetTop) {
        setHeaderTheme({ 
          bg: 'bg-magic-blue', 
          text: 'text-white', 
          shadow: 'dark:shadow-[0_10px_40px_-10px_rgba(0,56,255,0.6)]',
          blobColor: 'bg-magic-blue'
        });
      } else if (projects && scrollPos >= projects.offsetTop) {
        setHeaderTheme({ 
          bg: 'bg-magic-orange', 
          text: 'text-white', 
          shadow: 'dark:shadow-[0_10px_40px_-10px_rgba(255,77,0,0.6)]',
          blobColor: 'bg-magic-orange'
        });
      } else if (whatWeDo && scrollPos >= whatWeDo.offsetTop) {
        setHeaderTheme({ 
          bg: 'bg-magic-orange', 
          text: 'text-white', 
          shadow: 'dark:shadow-[0_10px_40px_-10px_rgba(255,77,0,0.6)]',
          blobColor: 'bg-magic-orange'
        });
      } else {
        setHeaderTheme({ 
          bg: 'bg-transparent', 
          text: 'text-magic-black dark:text-off-white', 
          shadow: '',
          blobColor: 'bg-magic-orange'
        });
      }
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const toggleDarkMode = () => setIsDarkMode(!isDarkMode);

  return (
    <div className="relative overflow-hidden selection:bg-magic-orange selection:text-white bg-off-white dark:bg-magic-dark transition-colors duration-500 min-h-screen">

      {/* Dynamic Duo-Blob Background */}
      <div className="pointer-events-none fixed inset-0 z-0 overflow-hidden">
        <div 
          className={`absolute w-[80vw] h-[80vw] md:w-[50vw] md:h-[50vw] max-w-[700px] max-h-[700px] rounded-full blur-[80px] md:blur-[120px] opacity-30 md:opacity-40 dark:opacity-60 mix-blend-normal dark:mix-blend-screen transition-colors duration-1000 ease-in-out ${headerTheme.blobColor}`}
          style={{
            left: blob1Pos.x,
            top: blob1Pos.y,
            transform: 'translate(-50%, -50%)',
            willChange: 'left, top'
          }}
        />
        <div 
          className={`absolute w-[70vw] h-[70vw] md:w-[40vw] md:h-[40vw] max-w-[600px] max-h-[600px] rounded-full blur-[100px] md:blur-[140px] opacity-20 md:opacity-30 dark:opacity-50 mix-blend-normal dark:mix-blend-screen transition-colors duration-1000 ease-in-out ${headerTheme.blobColor}`}
          style={{
            left: blob2Pos.x,
            top: blob2Pos.y,
            transform: 'translate(-50%, -50%)',
            willChange: 'left, top'
          }}
        />
      </div>

      <Header 
        bgColor={`${headerTheme.bg} ${headerTheme.shadow}`} 
        textColor={headerTheme.text} 
        lang={lang} 
        setLang={setLang} 
        isDarkMode={isDarkMode}
        toggleDarkMode={toggleDarkMode}
      />

      <main className="relative">
        <Hero lang={lang} />

        <Section id="what-we-do" title={t.whatWeDo.title} subtitle={t.whatWeDo.subtitle} className="bg-transparent py-16 md:py-32">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8 md:gap-12 mt-12">
            {t.whatWeDo.services.map((service, i) => (
              <div key={i} className="group pt-0 md:pt-4 transition-all duration-500">
                <span className="font-archivo text-xs md:text-sm uppercase tracking-widest mb-4 block text-magic-black/30 dark:text-off-white/30">0{i+1}</span>
                <h3 className="font-archivo text-2xl md:text-3xl uppercase tracking-tighter mb-4 md:mb-6 text-magic-black dark:text-off-white group-hover:translate-x-2 transition-transform duration-300">{service.title}</h3>
                <p className="text-base md:text-lg text-magic-black/60 dark:text-off-white/60 leading-relaxed font-medium">{service.desc}</p>
              </div>
            ))}
          </div>
        </Section>

        <ProjectsGrid lang={lang} />

        <Section 
          id="studio" 
          title={t.studio.title} 
          subtitle={t.studio.subtitle} 
          className="bg-magic-black/95 text-off-white dark:bg-transparent transition-all duration-700 py-16 md:py-48"
        >
          <div className="flex flex-col lg:flex-row gap-8 md:gap-16 items-center">
            <div className="w-full lg:w-1/2">
              <div className="relative group overflow-hidden rounded-sm">
                <img src="https://images.unsplash.com/photo-1497366216548-37526070297c?auto=format&fit=crop&q=80&w=1200" alt="Studio" className="w-full grayscale group-hover:grayscale-0 transition-all duration-700 scale-105 group-hover:scale-100 aspect-video md:aspect-auto object-cover" />
                <div className="absolute inset-0 bg-magic-orange/10 opacity-0 group-hover:opacity-100 transition-opacity duration-700"></div>
              </div>
            </div>
            <div className="w-full lg:w-1/2 space-y-6 md:space-y-8 text-magic-black dark:text-off-white">
              <p className="font-editorial text-3xl md:text-4xl italic text-inherit leading-tight drop-shadow-sm opacity-90">{t.studio.p1}</p>
              <p className="text-lg md:text-xl text-inherit opacity-60 font-light leading-relaxed">{t.studio.p2}</p>
              <button className="w-full md:w-auto bg-magic-orange text-white font-archivo uppercase tracking-widest px-10 py-5 hover:bg-orange-600 transition-all duration-300 shadow-[0_10px_40px_rgba(255,77,0,0.3)] hover:shadow-[0_15px_50px_rgba(255,77,0,0.5)] active:scale-95">
                {t.studio.startProject}
              </button>
            </div>
          </div>
        </Section>

        <Section id="contact" title={t.contact.title} subtitle={t.contact.subtitle} className="bg-transparent py-16 md:py-32">
          <div className="flex flex-col md:flex-row gap-12 md:gap-16 mt-12">
            <div className="md:w-1/2 space-y-10 md:space-y-12">
              <div>
                <span className="font-archivo text-xs uppercase tracking-widest text-magic-black/30 dark:text-off-white/30 block mb-4">{t.contact.emailLabel}</span>
                <a href="mailto:hello@magicpop.studio" className="font-archivo text-2xl md:text-5xl uppercase tracking-tighter text-magic-black dark:text-off-white hover:text-magic-orange transition-colors duration-300 underline underline-offset-8 decoration-transparent hover:decoration-magic-orange break-words">hello@magicpop.studio</a>
              </div>
              <div>
                <span className="font-archivo text-xs uppercase tracking-widest text-magic-black/30 dark:text-off-white/30 block mb-4">{t.contact.followLabel}</span>
                <div className="flex gap-6 md:gap-8 font-archivo uppercase text-xs md:text-sm tracking-widest text-magic-black dark:text-off-white">
                  <a href="#" className="hover:text-magic-blue transition-colors">Instagram</a>
                  <a href="#" className="hover:text-magic-blue transition-colors">Behance</a>
                </div>
              </div>
            </div>
            <div className="md:w-1/2 bg-yellow-400 p-8 md:p-12 flex flex-col justify-center shadow-[0_30px_80px_-20px_rgba(250,204,21,0.3)] rounded-sm">
              <p className="font-editorial text-3xl md:text-5xl text-magic-black italic leading-tight mb-8">{t.contact.footerNote}</p>
              <button className="bg-magic-black text-off-white font-archivo uppercase tracking-widest px-10 py-5 hover:bg-magic-black/80 transition-all duration-300 self-start active:scale-95">
                {t.studio.startProject}
              </button>
            </div>
          </div>
        </Section>
      </main>

      <footer className="relative z-10 bg-magic-black dark:bg-magic-dark py-12 md:py-24 px-6 md:px-12 text-off-white flex flex-col md:flex-row justify-between items-center gap-8 transition-colors duration-500">
        <div className="font-archivo text-xl uppercase tracking-tighter text-off-white">Magic Pop<span className="font-editorial lowercase text-lg ml-1">studio</span></div>
        <div className="text-[10px] md:text-xs uppercase tracking-widest text-off-white/30 text-center md:text-left">© 2024 Magic Pop Studio. RAL 8022 Palette.</div>
