            onClick={() => setSelectedProject(null)}
            className="fixed top-24 right-6 md:top-32 md:right-12 z-[110] bg-magic-pink text-magic-black w-14 h-14 md:w-20 md:h-20 flex items-center justify-center rounded-full hover:scale-110 active:scale-90 transition-all duration-300 shadow-[0_20px_50px_rgba(255,183,213,0.5)] backdrop-blur-md"
