import React, { useState } from 'react';
import { Language } from '../types';
import { TRANSLATIONS } from '../constants';

interface HeaderProps {
  bgColor: string;
  textColor: string;
  lang: Language;
  setLang: (lang: Language) => void;
  isDarkMode: boolean;
  toggleDarkMode: () => void;
  onNavClick?: () => void;
}

const Header: React.FC<HeaderProps> = ({ bgColor, textColor, lang, setLang, isDarkMode, toggleDarkMode, onNavClick }) => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const t = TRANSLATIONS[lang].nav;

  const navItems = [
    { label: t.projects, href: '#projects' },
    { label: t.whatWeDo, href: '#services' },
    { label: t.studio, href: '#about' },
    { label: t.contact, href: '#contact' },
  ];

  const handleNavItemClick = (e: React.MouseEvent<HTMLAnchorElement>, href: string) => {
    e.preventDefault();

    // 1. Close Modals & Mobile Menu
    if (onNavClick) onNavClick();
    setIsMenuOpen(false);

    // 2. Smooth Scroll Logic
    const targetId = href.replace('#', '');
    const element = document.getElementById(targetId);

    if (element) {
      const headerOffset = 80; // Adjusted for fixed header
      const elementPosition = element.getBoundingClientRect().top;
      const offsetPosition = elementPosition + window.pageYOffset - headerOffset;

      window.scrollTo({
        top: offsetPosition,
        behavior: 'smooth'
      });

      // Update URL hash without jump
      window.history.pushState(null, '', href);
    }
  };

  return (
    <>
      <header 
        className={`fixed top-0 left-0 w-full z-[100] transition-all duration-700 ease-in-out px-6 md:px-12 py-5 md:py-6 flex justify-between items-center ${bgColor}`}
      >
        <div className={`font-archivo text-2xl md:text-3xl tracking-tighter uppercase ${textColor} transition-colors duration-700 relative z-[110]`}>
          <a 
            href="#hero" 
            onClick={(e) => handleNavItemClick(e, '#hero')} 
            className="hover:opacity-60 transition-opacity"
          >
            Magic Pop<span className="font-editorial lowercase text-xl md:text-2xl ml-1">studio</span>
          </a>
        </div>

        <div className="flex items-center gap-4 md:gap-10">
          <nav className="hidden md:flex gap-10">
            {navItems.map((item) => (
              <a
                key={item.label}
                href={item.href}
                onClick={(e) => handleNavItemClick(e, item.href)}
                className={`font-archivo text-xs uppercase tracking-widest hover:opacity-60 transition-all duration-300 ${textColor}`}
              >
                {item.label}
              </a>
            ))}
          </nav>

