      {/* Project Detail Modal - Boosted z-index to cover header */}
      {selectedProject && (
        <div className="fixed inset-0 z-[200] bg-off-white dark:bg-magic-dark overflow-hidden animate-in duration-500">

          {/* FIXED CLOSE BUTTON: Stays visible at all times, high z-index */}
          <button 
            onClick={() => setSelectedProject(null)}
            className="fixed top-6 right-6 md:top-12 md:right-12 z-[250] bg-magic-pink text-magic-black w-14 h-14 md:w-20 md:h-20 flex items-center justify-center rounded-full hover:scale-110 active:scale-90 transition-all duration-300 shadow-[0_20px_50px_rgba(255,183,213,0.5)] backdrop-blur-sm"
