            </div>
          </div>
        ))}
      </div>

      {/* Project Detail Modal */}
      {selectedProject && (
        <div className="fixed inset-0 z-[200] bg-off-white dark:bg-magic-dark overflow-hidden animate-in duration-500">

          <button 
            onClick={() => setSelectedProject(null)}
